  FILTER(CONTAINS(LCASE(STR(?label)), "areas") || CONTAINS(LCASE(STR(?label)), "united") || CONTAINS(LCASE(STR(?label)), "states") || CONTAINS(LCASE(STR(?label)), "sex") || CONTAINS(LCASE(STR(?label)), "marriages") || CONTAINS(LCASE(STR(?label)), "case") || CONTAINS(LCASE(STR(?label)), "edith") || CONTAINS(LCASE(STR(?label)), "edie") || CONTAINS(LCASE(STR(?label)), "windsor") || CONTAINS(LCASE(STR(?label)), "main") || CONTAINS(LCASE(STR(?label)), "plaintiff"))
}
